function pickPayload(j) {
  if (!j || typeof j !== 'object') return {};
  const inner = j.body;
  if (inner != null && typeof inner === 'object' && !Array.isArray(inner)) return inner;
  if (typeof inner === 'string') {
    try {
      return JSON.parse(inner);
    } catch {
      return {};
    }
  }
  return j;
}
const b = pickPayload($input.first().json);
const raw = String(b.agentBaseUrl ?? b.infra?.agentBaseUrl ?? '').trim().replace(/\/+$/, '');
if (!raw) {
  throw new Error(
    'Missing agentBaseUrl. Keys on item: ' + Object.keys(b).join(', '),
  );
}
const rl = raw.toLowerCase();
if (rl.includes('developers.hostinger.com') || rl.includes('hostinger.com/api')) {
  throw new Error(
    'agentBaseUrl looks like Hostinger API (' +
      raw +
      '), not your deploy-agent. Set bot_deployment_infra.agent_base_url to the HTTPS origin of your VPS deploy-agent (e.g. https://deploy.yourdomain.com).',
  );
}
const url = raw + '/post-deploy';
const token = String(b.stackAgent?.bearerToken ?? '').trim();
if (!token) {
  throw new Error('Missing stackAgent.bearerToken (save Stack agent bearer token in Deploy bot → Provider / stack settings).');
}
return [
  {
    json: {
      postUrl: url,
      bearerToken: token,
      botDeploymentId: b.botDeploymentId,
      customerLabel: b.customerLabel,
    },
  },
];
